changeSet.sql:
CREATE TABLE likelihood_metrics
(
	id serial,
	risk_model_id integer NOT NULL,
	question_id integer NOT NULL,
	question_weight_id integer NOT NULL,
	risk_type_id integer DEFAULT NULL,
	vendor_id integer DEFAULT NULL,
	created_by_id integer DEFAULT NULL,
	updated_by_id integer DEFAULT NULL,
	created_at timestamp without time zone NOT NULL DEFAULT now(),
	updated_at timestamp without time zone NOT NULL DEFAULT now(),
	CONSTRAINT pk_likelihood_metrics PRIMARY KEY (id)
	, CONSTRAINT fk_likelihood_metrics_to_risk_model FOREIGN KEY (risk_model_id) REFERENCES risk_models (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_likelihood_metrics_to_question FOREIGN KEY (question_id) REFERENCES qualitative_questions (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_likelihood_metrics_to_weight FOREIGN KEY (question_weight_id) REFERENCES question_weights (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_likelihood_metrics_to_risk_type FOREIGN KEY (risk_type_id) REFERENCES risk_types (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_likelihood_metrics_to_vendor FOREIGN KEY (vendor_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_likelihood_metrics_to_created_by FOREIGN KEY (created_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_likelihood_metrics_to_updated_by FOREIGN KEY (updated_by_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_likelihood_metrics_risk_model ON likelihood_metrics (risk_model_id);
CREATE INDEX i_likelihood_metrics_question ON likelihood_metrics (question_id);
CREATE INDEX i_likelihood_metrics_weight ON likelihood_metrics (question_weight_id);
CREATE INDEX i_likelihood_metrics_risk_type ON likelihood_metrics (risk_type_id);
CREATE INDEX i_likelihood_metrics_vendor ON likelihood_metrics (vendor_id);
CREATE INDEX i_likelihood_metrics_created_at ON likelihood_metrics (created_at);
CREATE INDEX i_likelihood_metrics_created_by ON likelihood_metrics (created_by_id);
CREATE INDEX i_likelihood_metrics_updated_by ON likelihood_metrics (updated_by_id);
